import React from 'react';

import ColoredNumberDisplay from '@appSharedComponents/ColoredNumberDisplay';

import * as styles from './positionListItem.module.css';

/**
 * Displays the trade position (as part of it's listing)
 * @param {Object} props Props passed to this component
 * @param {?('div'|'li'|'button')} [props.wrapperElement='div'] HTML element to use for the wrapping elm, Defaualts to 'div'
 * @param {string} props.tradingsymbol Trading symbol of the position
 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} props.exchange Exchange this instrument is listed under
 * @param {number} props.qty Quantity purchased
 * @param {number} props.avg Average entry price
 * @param {number} props.ltp Last Traded Price
 * @param {?('B'|'S')} [props.direction='B'] Trade direction. 'B' for buy trade, 'S' for sell trade
 * @param {Date} props.expiry Expiry date
 */
export default function PositionListItem({ wrapperElement: WrapElm = 'div', tradingsymbol, exchange, qty, avg, ltp, direction, expiry, className, ...props }) {
	//here calculate pnl
	// const posPnl = (direction === 'S' ? avg - ltp : ltp - avg) * qty;
	let posPnl = null;
	if (ltp) {
		posPnl = (direction === 'S' ? avg - ltp : ltp - avg) * qty;
	}
	return (
		<WrapElm
			className={`${styles.positionC} ${direction === 'S' ? styles.isSell : styles.isBuy}${
				className && typeof className === 'string' && className.trim() !== '' ? ' ' + className : ''
			}`}
			{...props}
		>
			<div className={styles.dataRow}>
				{exchange ? <span data-exchange={exchange}>{tradingsymbol}</span> : <span>{tradingsymbol}</span>}
				<ColoredNumberDisplay currentVal={posPnl} baseVal={0} />
			</div>
			<div className={styles.metaDataRow}>
				<span className={styles.qty}>{qty}</span>
				<span className={styles.avg}>{avg}</span>
				<span className={styles.ltp}>
					{/* <PreventRerenderIfValueInvalid value={ltp} /> */}
					{ltp}
				</span>
				{/* We use memo for above value wherein we prevent rerender if value is null, thus displaying previous tick value instead of null*/}
			</div>
		</WrapElm>
	);
}
