import React, { useContext, useState } from 'react';

// import ColoredNumberDisplay from '@components/ColoredNumberDisplay';
import Button from '@components/ui/Button';
import TextInput from '@components/ui/TextInput';
import PositionListItem from '@appSharedComponents/tradePosition/PositionListItem';

import { ToastNotificationContext } from '@providers/ToastNotification';
import { UserContext } from '@providers/User';
import { AppDataIndexedDbContext } from '@appSharedProviders/AppIndexedDb';

import * as styles from './exitTradePositionDialog.module.css';

/**
 * Component that displays the Trade Position exit dialaog
 * @param {Object} props Props passed to this component
 * @param {string} props.tradingsymbol Instrument trading symbol
 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} props.exchange Exchange where this instrument is listed / traded
 * @param {number} props.purchasdQty Purchased quantity
 * @param {?number} [props.lotSize = 1] Lot size
 * @param {number} props.avgEntryPrice Average entry price
 * @param {number} props.ltp LTP of the instrument
 * @param {?('B'|'S')} [props.direction='B'] Trade direction 'B' for BUY trade and 'S' for SELL trade
 * @param {(Object)=>{}} [props.doOnSuccessfulExit] Callback fn to execute once position is exited successfully, either partially or fully. ExitedPos is the argument
 * @param {()=>{}} props.closeDialog Go back button. Effectively, closes the dialog. Useful in closing bottom sheet
 */
export default function ExitTradePositionDialog({
	tradingsymbol,
	exchange,
	purchasdQty,
	lotSize = 1,
	avgEntryPrice,
	ltp,
	direction = 'B',
	doOnSuccessfulExit,
	closeDialog,
}) {
	const [qty, setQty] = useState(/** @type {number} */ (purchasdQty));
	const [qtyErr, setQtyErr] = useState(/** @type {string} */ (''));
	const [isWip, setIsWip] = useState(/** @type {Boolean} */ (false));

	const { notify } = useContext(ToastNotificationContext);
	const { checkIfPlanActive } = useContext(UserContext);
	const { exitPosition } = useContext(AppDataIndexedDbContext);

	/** Checks if quantity to be exited is <= purchased quantity and is a multiple of lot-size */
	const _chkForQtyErrs = (qtyParam) => {
		// if (qtyParam === undefined) qtyParam = qty;	//read default value from state
		if (isNaN(Number(qtyParam))) return 'Quantity should be a number';
		if (!Number.isInteger(qtyParam)) return 'Quantity should be an integer';
		if (qtyParam > purchasdQty) return 'Quantity cannot be more ' + purchasdQty;
		if (qtyParam < lotSize) return 'Quantity cannot be less than lot-size of ' + lotSize;
		if (qtyParam % lotSize !== 0) return 'Quantity should be a multiple of ' + lotSize;
		return '';
	};
	const validate_n_setQty = (e) => {
		setQtyErr(_chkForQtyErrs(Number(e.target.value)));
		setQty(Number(e.target.value));
	};

	/**
	 * Exit/partial-exit trade position in IndexedDB
	 * @returns {Promise<boolean>}
	 */
	const doExit = async () => {
		if (!ltp) {
			notify('Error inferring exit price', 'err');
			return false;
		}
		const qtyErr = _chkForQtyErrs(qty);
		if (isWip) return false;
		if (qtyErr !== '') {
			notify(qtyErr, 'err');
			return false;
		}
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			setIsWip(true);
			const exitedPos = await exitPosition(tradingsymbol, exchange, direction === 'S', ltp, qty);
			if (!exitedPos) throw new Error('Failed to exit position');
			//here update the state in positions component or provider
			doOnSuccessfulExit && typeof doOnSuccessfulExit === 'function' && doOnSuccessfulExit(exitedPos);

			notify('Trade position exited successfully', 'success');
			closeDialog && typeof closeDialog === 'function' && closeDialog();
			return true;
		} catch (err) {
			notify(err.message || 'Error exiting trade position', 'err');
			return false;
		} finally {
			setIsWip(false);
		}
	};

	// if(!ltp) return <div>Unable to read LTP for this instrument</div>
	return (
		<div className={styles.tradePositionMgmtC}>
			{/* <div className={styles.posInfo}>
				<span>{tradingsymbol}</span>
				<ColoredNumberDisplay currentVal={ltp} baseVal={closePrice} />
			</div> */}
			<PositionListItem
				className={styles.posInfo}
				tradingsymbol={tradingsymbol}
				exchange={exchange}
				qty={purchasdQty}
				avg={avgEntryPrice}
				ltp={ltp}
				direction={direction}
			/>
			<div>
				<TextInput
					type="number"
					title="Exit Quantity"
					placeholder="Exit Quantity"
					value={qty.toString()}
					onChange={validate_n_setQty}
					error={qtyErr}
					actionPane={() => <span className={styles.totalQty}>{purchasdQty}</span>}
				/>
			</div>
			<div className={styles.posFtr}>
				{/* <Button variant="tertiary" isDark={true} onClick={closeDialog}>
					Cancel
				</Button> */}
				{/* <Button variant={direction === 'B' ? 'buy' : direction === 'S' ? 'sell' : 'primary'} onClick={doExit} isWip={isWip} wipText="Exiting">
					Exit
				</Button> */}
				<Button variant="primary" onClick={doExit} isWip={isWip} wipText="Exiting">
					Exit
				</Button>
			</div>
		</div>
	);
}
