import React, { useContext } from 'react';

import ColoredNumberDisplay from '@appSharedComponents/ColoredNumberDisplay';
// import PreventRerenderIfValueInvalid from '@components/PreventRerenderIfValueInvalid';
import { formatPriceInIndianStyle } from '@utils';
import Button from '@components/ui/Button';
import { ToastNotificationContext } from '@providers/ToastNotification';

import * as styles from './watchlistItem.module.css';

/**
 * Displays the marketwatch instrument (as part of watchlist)
 * @param {Object} props Props passed to this component
 * @param {?('div'|'li'|'button')} [props.wrapperElement='div'] HTML element to use for the wrapping elm, Defaualts to 'div'
 * @param {string} props.tradingsymbol Trading symbol of the instrument
 * @param {string} props.entityName Name of the company or INDEX for the instrument
 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} props.exchange Exchange the instrument is listed under
 * @param {('INDICES'|'NFO-OPT'|'NFO-FUT'|'NSE-EQ'|'BSE-EQ')} props.segment Segment the instrument belongs to
 * @param {number} props.ltp Last Traded Price
 * @param {number} props.closePrice Close price from last trading day session
 * @param {string} [props.className] Additional classname to append to the container
 * @param {boolean} [props.isExpandedView=false] Whether to show the expanded view with buttons for buy or sell and remove from listing
 * @param {()=>{}} props.onSellClick Callback function to execute when user clicks on SELL button in expanded view
 * @param {()=>{}} props.onBuyClick Callback function to execute when user clicks on BUY button in expanded view
 * @param {()=>{}} props.onRemoveClick Callback function to execute when user clicks on remove button in expanded view
 * @param {()=>{}} props.closeExpandedView Callback function to execute to close expanded view
 */
export default function WatchlistItem({
	wrapperElement: WrapElm = 'div',
	tradingsymbol,
	entityName,
	exchange,
	segment,
	ltp,
	closePrice,
	className,
	isExpandedView,
	onSellClick,
	onBuyClick,
	onRemoveClick,
	closeExpandedView,
	...props
}) {
	const { notify } = useContext(ToastNotificationContext);
	return (
		<WrapElm className={`${styles.wlItmC}${className && typeof className === 'string' && className.trim() !== '' ? ' ' + className : ''}`} {...props}>
			<div className={styles.dataRow}>
				<span>{tradingsymbol}</span>
				{/* <span>{exchange === 'NSE' ? entityName : tradingsymbol}</span> */}
				<ColoredNumberDisplay currentVal={ltp} baseVal={closePrice} />
			</div>
			<div className={styles.metaDataRow}>
				<span>{`${exchange}${entityName ? ' | ' + entityName : ''}`}</span>
				{/* <span>{`${exchange}${exchange === 'NFO' || exchange === 'MCX' ? (entityName ? ' | ' + entityName : '') : ''}`}</span> */}
				<span>
					{/* <PreventRerenderIfValueInvalid value={formatPriceInIndianStyle(ltp - closePrice)} /> */}
					{/* We use memo for above value wherein we prevent rerender if value is null, thus displaying previous tick value instead of null*/}
					{formatPriceInIndianStyle(ltp - closePrice)}
				</span>
			</div>
			{isExpandedView && (
				<div className={styles.instrumentCtaC}>
					<Button
						variant="tertiary"
						isDark={true}
						icon="chevron-up"
						onClick={(e) => {
							closeExpandedView?.();
							e.stopPropagation(); //prevents event on parent elm from firing
						}}
					/>
					{/* {segment !== 'INDICES' && (
						<>
							<Button
								variant="sell"
								className={styles.mainBtn}
								onClick={() => {
									notify('Sell functionality coming soon!');
								}}
							>
								SELL
							</Button>
							<Button
								variant="buy"
								className={styles.mainBtn}
								onClick={(e) => {
									onBuyClick?.();
									closeExpandedView?.(); //close the expanded view
									e.stopPropagation();
								}}
							>
								BUY
							</Button>
						</>
					)} */}
					<Button
						variant="sell"
						className={styles.mainBtn}
						onClick={() => {
							notify('Sell functionality coming soon!');
						}}
					>
						SELL
					</Button>
					<Button
						variant="buy"
						className={styles.mainBtn}
						onClick={(e) => {
							onBuyClick?.();
							closeExpandedView?.(); //close the expanded view
							e.stopPropagation();
						}}
					>
						BUY
					</Button>
					<Button
						variant="tertiary"
						isDark={true}
						icon="trash-2"
						onClick={(e) => {
							onRemoveClick?.();
							e.stopPropagation(); //prevents event on parent elm from firing
						}}
					/>
				</div>
			)}
		</WrapElm>
	);
}
